def pip_install_packages(packages):
    """
    Execute pip commands to install additional packages needed at install time.
    This handles packages that need to be available during the setup process
    or that require special pip flags.
    """
    if not packages:
        return

    for package_spec in packages:
        if isinstance(package_spec, str):
            # Simple package name/spec
            cmd = [sys.executable, "-m", "pip", "install", package_spec]
            flags = []
        elif isinstance(package_spec, dict):
            # Dict with package name and optional pip flags
            cmd = [sys.executable, "-m", "pip", "install"]
            flags = package_spec.get("flags", [])
            if isinstance(flags, list):
                cmd.extend(flags)
            cmd.append(package_spec["name"])
        else:
            print(f"[setup.py] Skipping unrecognized package spec: {package_spec}")
            continue

        try:
            print(f"[setup.py] Running: {' '.join(cmd)}")
            subprocess.check_call(cmd)
            print(f"[setup.py] Successfully installed: {cmd[-1]}")
        except subprocess.CalledProcessError as e:
            print(f"[setup.py] Warning: Failed to install {cmd[-1]}: {e}")
        except Exception as e:
            print(f"[setup.py] Error installing {cmd[-1]}: {e}")


